                    {courseDetails.teacher.name?.charAt(0).toUpperCase()}
                  </div>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 14 }}>{courseDetails.teacher.name}</div>
                    <div style={{ fontSize: 12, color: T.muted }}>{courseDetails.teacher.email}</div>
