            </Card>

            {/* Classmates Card */}
            <Card style={{ padding: 20 }}>
              <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 14 }}>
                👥 Classmates ({courseDetails?.classmateCount ?? 0})
