                const isOverdue = a.dueDate && new Date(a.dueDate) < new Date();

                return (
                  <Card key={a.id} style={{ padding: 18, borderLeft: a.submissionStatus === "RESUBMISSION_REQUESTED" ? `4px solid ${T.accentY}` : undefined }}>
