                      <div style={{ flex: 1 }}>
                        <div style={{ display: "flex", gap: 6, alignItems: "center", marginBottom: 6 }}>
                          <Badge type="primary">{a.taskType || "Homework"}</Badge>
                          {a.submissionStatus === "RESUBMISSION_REQUESTED" ? (
                            <Badge type="warning">Resubmission Requested</Badge>
