            </div>

            <Btn variant="primary" full onClick={handleSubmit} disabled={submitting}>
              {submitting ? "Submitting…" : selected.submissionStatus === "RESUBMISSION_REQUESTED" ? "Update and Submit Task" : "Submit Assignment"}
            </Btn>
          </div>
        )}
      </Modal>
    </div>
  );
};

